--[[
    Bad Apple!! for CC:Tweaked
    39x15, 2175 frames, 10.0 FPS
]]

local W,H=39,15
local FPS=10.0
local BPR=5
local N=2175

local function getDisplay()
    local best=term
    local bW,bH=term.getSize()
    for _,s in ipairs({"top","bottom","left","right","front","back"})do
        local ok,m=pcall(peripheral.wrap,s)
        if ok and m and m.getSize then
            pcall(function()m.setTextScale(1)end)
            local w,h=m.getSize()
            if w*h>bW*bH then best=m;bW=w;bH=h end
        end
    end
    return best,bW,bH
end

local function draw(d,fidx,data)
    local off=(fidx-1)*BPR*H+1
    for y=1,H do
        local text,fg,bg={},{},{}
        local x=1
        for i=1,BPR do
            local b=string.byte(data,off)
            off=off+1
            if not b then break end
            for bit=0,7 do
                if x>W then break end
                local mask=2^(7-bit)
                local white=(math.floor(b/mask)%2)==1
                if white then
                    text[#text+1]=" "
                    fg[#fg+1]="f"
                    bg[#bg+1]="0"
                else
                    text[#text+1]=" "
                    fg[#fg+1]="0"
                    bg[#bg+1]="f"
                end
                x=x+1
            end
        end
        d.setCursorPos(1,y)
        d.blit(table.concat(text),table.concat(fg),table.concat(bg))
    end
end

